<span class="line">    PARAMETERS  <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token number">1U</span> <span class="token operator">&lt;&lt;</span> <span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">,</span>   <span class="token comment">// 파라미터 유효성</span></span>
